import XCTest@testable import MovieQuizfinal class MovieQuizPresenterTests: XCTestCase {        func testPresenterConvertModel() throws {        let viewControllerMock = MovieQuizViewControllerMock()        let presenter = MovieQuizPresenter(viewController: viewControllerMock)                let question = QuizQuestion(            image: Data(),            text: "Рейтинг этого фильма больше чем 6?",            correctAnswer: true        )        let viewModel = presenter.convert(model: question)                XCTAssertNotNil(viewModel.image)        XCTAssertEqual(viewModel.question, "Рейтинг этого фильма больше чем 6?")        XCTAssertEqual(viewModel.questionNumber, "1/10")    }}// MARK: - MovieQuizViewControllerMockfinal class MovieQuizViewControllerMock: MovieQuizViewControllerProtocol {    func show(quiz step: QuizStepViewModel) {}    func show(quiz result: QuizResultsViewModel) {}    func highlightImageBorder(isCorrectAnswer: Bool) {}    func showLoadingIndicator() {}    func hideLoadingIndicator() {}    func showNetworkError(message: String) {}}